import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"د WebDAV Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/webdav.md","filePath":"ps/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"ps/upload/webdav.md"};function c(p,e,h,u,b,f){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="د-webdav-channel-اضافه-کول" tabindex="-1">د WebDAV Channel اضافه کول <a class="header-anchor" href="#د-webdav-channel-اضافه-کول" aria-label="Permalink to &quot;د WebDAV Channel اضافه کول&quot;">​</a></h1><h2 id="کله-مناسب-دی" tabindex="-1">کله مناسب دی <a class="header-anchor" href="#کله-مناسب-دی" aria-label="Permalink to &quot;کله مناسب دی&quot;">​</a></h2><p>WebDAV channel هغه وخت وکاروئ چې:</p><ul><li>NAS، cloud drive یا object storage service لرئ چې WebDAV endpoint ورکوي.</li><li>غواړئ uploaded images په خپل WebDAV directory کې وساتئ.</li><li>غواړئ credentials د frontend پر ځای په D1 <code>upload_channels</code> table کې خوندي شي.</li></ul><h2 id="د-پیل-مخکې-اړتیاوې" tabindex="-1">د پیل مخکې اړتیاوې <a class="header-anchor" href="#د-پیل-مخکې-اړتیاوې" aria-label="Permalink to &quot;د پیل مخکې اړتیاوې&quot;">​</a></h2><table tabindex="0"><thead><tr><th>اړتیا</th><th>موخه</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>server-side WebDAV URL، لکه <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>WebDAV service ته د sign in لپاره.</td></tr><tr><td>Password</td><td>WebDAV service ته د sign in لپاره.</td></tr><tr><td>Authentication mode</td><td>default <code>Basic</code> دی. <code>Digest</code> یا auto negotiation یوازې هغه وخت وکاروئ چې server یې وغواړي.</td></tr><tr><td>Storage directory</td><td>هغه directory چې files پکې ساتل کېږي. default <code>imgbed</code>.</td></tr></tbody></table><h2 id="چېرته-یې-اضافه-کړو" tabindex="-1">چېرته یې اضافه کړو <a class="header-anchor" href="#چېرته-یې-اضافه-کړو" aria-label="Permalink to &quot;چېرته یې اضافه کړو&quot;">​</a></h2><ol><li>System Settings پرانیزئ.</li><li>Upload Settings ته ولاړ شئ.</li><li>په پورته ښي لوري کې Add Channel کلیک کړئ.</li><li><code>WebDAV</code> وټاکئ.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>څه کوي</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>د دې WebDAV channel لپاره نوم، لکه <code>koofr</code> یا <code>nas</code>.</td><td>Yes</td></tr><tr><td>Endpoint</td><td>بشپړ WebDAV endpoint د <code>https://</code> سره.</td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username.</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password.</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>عموماً <code>Basic</code>; که server digest authentication غواړي، <code>Digest</code> وکاروئ.</td><td>Yes</td></tr><tr><td>Storage directory</td><td>هغه directory چې files پکې ساتل کېږي. default <code>imgbed</code>.</td><td>No</td></tr></tbody></table><h2 id="مثال-fie-nl-tab-digital" tabindex="-1">مثال: fie.nl.tab.digital <a class="header-anchor" href="#مثال-fie-nl-tab-digital" aria-label="Permalink to &quot;مثال: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-password-جوړ-کړئ" tabindex="-1">1. App Password جوړ کړئ <a class="header-anchor" href="#_1-app-password-جوړ-کړئ" aria-label="Permalink to &quot;1. App Password جوړ کړئ&quot;">​</a></h3><p>د account security settings پرانیزئ، application passwords ومومئ او app password نوی جوړ کړئ.</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>له جوړېدو وروسته app password copy او خوندي کړئ. عموماً یوازې یو ځل ښودل کېږي.</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-په-imgbed-کې-webdav-configuration-ډک-کړئ" tabindex="-1">2. په ImgBed کې WebDAV Configuration ډک کړئ <a class="header-anchor" href="#_2-په-imgbed-کې-webdav-configuration-ډک-کړئ" aria-label="Permalink to &quot;2. په ImgBed کې WebDAV Configuration ډک کړئ&quot;">​</a></h3><p>ImgBed ته بېرته ولاړ شئ او WebDAV channel اضافه کړئ:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>هغه WebDAV URL چې <code>https://fie.nl.tab.digital/</code> یې درکوي.</td></tr><tr><td>Username</td><td>ستاسې WebDAV username.</td></tr><tr><td>Password</td><td>همدا app password چې تازه مو جوړ کړی.</td></tr><tr><td>Authentication mode</td><td>په ډېرو حالتونو کې له <code>Basic</code> څخه پیل کړئ.</td></tr><tr><td>Storage directory</td><td>default <code>imgbed</code>; custom directory هم کارولای شئ.</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="د-لویو-files-د-upload-چلند" tabindex="-1">د لویو Files د Upload چلند <a class="header-anchor" href="#د-لویو-files-د-upload-چلند" aria-label="Permalink to &quot;د لویو Files د Upload چلند&quot;">​</a></h2><p>WebDAV channel اوس real session-based chunked upload کاروي.</p><p>کوچني files د یو complete file په توګه upload کېږي. له 64 MiB څخه لوی files په اتومات ډول د شاوخوا 10 MiB chunks ته وېشل کېږي او remote chunk directory ته upload کېږي.</p><p>WebDAV service ته اړتیا نشته چې <code>partial update</code> یا offset-based writes support کړي. ImgBed chunks په remote server کې یو لوی file ته merge نه کوي. پر ځای یې chunk manifest ساتي او د file request پر وخت chunks په ترتیب لولي.</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB یا کم</td><td>Normal upload</td><td>یو complete file</td></tr><tr><td>له 64 MiB څخه لوی</td><td>Real session chunked upload</td><td>chunk directory چې څو chunk files لري</td></tr></tbody></table><p>chunk directory یوازې remote storage layout اغېزمنوي. په ImgBed کې file URL نه بدلېږي. users لا هم د اصلي <code>/file/...</code> link له لارې file access کوي.</p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings پرانیزئ.</li><li>Add Channel کلیک کړئ.</li><li><code>WebDAV</code> وټاکئ.</li><li>یو پېژندل کېدونکی channel name ولیکئ، لکه <code>koofr</code>.</li><li>WebDAV endpoint ولیکئ، لکه <code>https://app.koofr.net/dav/Koofr</code>.</li><li>username او password ولیکئ.</li><li>authentication mode عموماً <code>Basic</code> پرېږدئ.</li><li>storage directory <code>imgbed</code> پرېږدئ، یا خپل directory ولیکئ.</li><li>Save کلیک کړئ.</li><li>له save وروسته channel card وګورئ، که capacity query available وي اجرا یې کړئ، او test file upload کړئ.</li></ol><h2 id="څنګه-یې-verify-کړو" tabindex="-1">څنګه یې Verify کړو <a class="header-anchor" href="#څنګه-یې-verify-کړو" aria-label="Permalink to &quot;څنګه یې Verify کړو&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>د verify طریقه</th></tr></thead><tbody><tr><td>Channel card appears</td><td>له Save وروسته باید WebDAV channel card په Upload Settings کې ښکاره شي.</td></tr><tr><td>Channel is enabled</td><td>د card په پورته ښي لوري کې switch باید on پاتې شي.</td></tr><tr><td>Credentials are saved</td><td>detail view باید Endpoint، username، authentication mode او storage directory وښيي.</td></tr><tr><td>Small file upload works</td><td>test image upload کړئ او وګورئ چې file په WebDAV directory کې ښکاري.</td></tr><tr><td>Large file rule works</td><td>له 64 MiB څخه لوی files chunked upload کاروي او remote chunk directory جوړوي.</td></tr><tr><td>Capacity query works</td><td>که server capacity information support کړي، query به used او total capacity وښيي.</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ولې-لوی-webdav-files-chunk-directory-جوړوي؟" tabindex="-1">ولې لوی WebDAV files chunk directory جوړوي؟ <a class="header-anchor" href="#ولې-لوی-webdav-files-chunk-directory-جوړوي؟" aria-label="Permalink to &quot;ولې لوی WebDAV files chunk directory جوړوي؟&quot;">​</a></h3><p>دا د لویو files لپاره اوسنی storage method دی.</p><p>له 64 MiB څخه لوی files په remote side کې یو لوی file ته merge نه کېږي. د chunk directory په بڼه ساتل کېږي. ImgBed chunk manifest record کوي او complete content د chunks په ترتیب لوستلو سره برابروي.</p><h3 id="که-large-file-upload-fail-شي،-لومړی-څه-وګورم؟" tabindex="-1">که large file upload fail شي، لومړی څه وګورم؟ <a class="header-anchor" href="#که-large-file-upload-fail-شي،-لومړی-څه-وګورم؟" aria-label="Permalink to &quot;که large file upload fail شي، لومړی څه وګورم؟&quot;">​</a></h3><p>Endpoint، username، password او storage directory لومړی وګورئ. بیا confirm کړئ چې WebDAV service directory creation، file writing او file reading allow کوي.</p><p>که capacity query fail شي خو small file upload کار کوي، ښايي server capacity reporting support نه کړي یا یې محدود کړی وي. دا لازماً د upload unavailable معنا نه لري.</p><h3 id="کوم-authentication-mode-وکاروم؟" tabindex="-1">کوم authentication mode وکاروم؟ <a class="header-anchor" href="#کوم-authentication-mode-وکاروم؟" aria-label="Permalink to &quot;کوم authentication mode وکاروم؟&quot;">​</a></h3><p>له <code>Basic</code> څخه پیل کړئ.</p><p>که server صریحاً digest authentication غواړي، <code>Digest</code> وکاروئ.</p><p>که ډاډه نه یاست، automatic negotiation وکاروئ.</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV endpoint, username او password چمتو کړئ</span></span>
<span class="line"><span>-&gt; Upload Settings پرانیزئ</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; WebDAV وټاکئ</span></span>
<span class="line"><span>-&gt; Endpoint / username / password ولیکئ</span></span>
<span class="line"><span>-&gt; authentication mode default Basic پرېږدئ</span></span>
<span class="line"><span>-&gt; storage directory default imgbed پرېږدئ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; capacity query</span></span>
<span class="line"><span>-&gt; test file upload</span></span></code></pre></div>`,44)])])}const k=r(s,[["render",c]]);export{y as __pageData,k as default};
